import numpy as np

def select_next_node(current_node, destination_node, unvisited_nodes, distance_matrix):
    priority_scores = {}
    for node in unvisited_nodes:
        distance_to_node = distance_matrix[current_node, node]
        heuristic_to_destination = distance_matrix[node, destination_node]
        priority_scores[node] = distance_to_node + heuristic_to_destination

    next_node = min(priority_scores, key=priority_scores.get)
    return next_node
